INSERT INTO `products` (`id`, `name`, `brand`, `category`, `price`, `was`, `sale_pct`, `badge`, `rating`, `reviews`, `stock`, `low_stock`, `kw`, `descr`, `long_desc`, `barcode`, `sku`, `size`, `how_to_use`, `ingredients`, `benefits`, `keywords`, `image`, `hover_image`, `gallery`, `feat_latest`, `feat_wellness`, `home_sort`, `sort`, `status`, `created_at`) VALUES ('la-roche-posay-lipikar-baume-ap-m-moisturising-b-63790','La Roche Posay Lipikar Baume AP+M Moisturising Body Balm For Dry & Eczema-Prone Skin, 200ml','La Roche-Posay','Body Care',22.93,NULL,NULL,'',0.0,0,20,5,'lipikar','Quickly absorbs to facilitate and speed up daily application. Non-greasy, non-sticky finish.','LIPIKAR Baume AP+M rebalances skin microbiome. It soothes skin immediately and reduces scratching. With its anti-relapse efficacy, it spaces out flare-ups. It nourishes skin, and restores the skin barrier. Formulated for babies, children, adults with very dry, eczema-prone or allergy-prone skin.','3337875763790','320MB3662','200 ml','Apply to face and body, once daily.\nFor enhanced results, use LIPIKAR Syndet or Huile lavante AP+ as cleanser and Stick AP+ in the day to soothe scratching.','AQUA / WATER • BUTYROSPERMUM PARKII BUTTER / SHEA BUTTER • GLYCERIN • DIMETHICONE • NIACINAMIDE • CETEARYL ALCOHOL • BRASSICA CAMPESTRIS SEED OIL / RAPESEED SEED OIL • GLYCERYL STEARATE • AMMONIUM POLYACRYLOYLDIMETHYL TAURATE • PEG-100 STEARATE • PROPANEDIOL • OPHIOPOGON JAPONICUS ROOT EXTRACT • PEG-20 METHYL GLUCOSE SESQUISTEARATE • SORBITAN TRISTEARATE • DIMETHICONOL • SODIUM CHLORIDE • MANNOSE • COCO-BETAINE • DISODIUM EDTA • CAPRYLOYL GLYCINE • CAPRYLYL GLYCOL • VITREOSCILLA FERMENT • CITRIC ACID • MALTODEXTRIN • XANTHAN GUM • TOCOPHEROL • PENTAERYTHRITYL TETRA-DI-T-BUTYL HYDROXYHYDROCINNAMATE','Quickly absorbs to facilitate and speed up daily application. Non-greasy, non-sticky finish.\nIt has a reinforced anti-scratching, anti-relapse efficacy and rebalances skin microbiome.\nTriple repair body moisturizer for dry to very dry skin that helps restore the skin’s protective barrier\nProvides long-lasting, 48-hour hydration\n Immediately soothes eczema-prone skin\nSuitable for new borns, children and adults.','Body moisturiser, Very dry, irritated, and eczema-prone skin\nSuitable for babies and sensitive skin, Lipikar','uploads/photo-pending.png','',NULL,0,0,0,87,'active','2026-07-08 09:35:13');
